import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Hero from '../components/Hero';
import ClassCard from '../components/ClassCard';
import TrainerCard from '../components/TrainerCard';
import MembershipCard from '../components/MembershipCard';
import api from '../services/api';
import { 
  FaDumbbell, 
  FaHeartbeat, 
  FaUsers, 
  FaClock,
  FaArrowRight 
} from 'react-icons/fa';
import './Home.css';

const Home = () => {
  const [classes, setClasses] = useState([]);
  const [trainers, setTrainers] = useState([]);
  const [memberships, setMemberships] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [classesRes, trainersRes, membershipsRes] = await Promise.all([
          api.get('/classes'),
          api.get('/trainers'),
          api.get('/memberships')
        ]);
        setClasses(classesRes.data.slice(0, 3));
        setTrainers(trainersRes.data.slice(0, 4));
        setMemberships(membershipsRes.data);
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const features = [
    {
      icon: <FaDumbbell />,
      title: 'Modern Equipment',
      description: 'State-of-the-art fitness equipment for all your workout needs.'
    },
    {
      icon: <FaHeartbeat />,
      title: 'Personal Training',
      description: 'Expert trainers to guide you through your fitness journey.'
    },
    {
      icon: <FaUsers />,
      title: 'Group Classes',
      description: 'Fun and engaging group classes for all fitness levels.'
    },
    {
      icon: <FaClock />,
      title: '24/7 Access',
      description: 'Work out on your schedule with round-the-clock access.'
    }
  ];

  return (
    <div className="home-page">
      <Hero />

      {/* Features Section */}
      <section className="section features-section">
        <div className="container">
          <div className="section-title">
            <h2>Why Choose <span>PowerFit</span>?</h2>
            <p>We provide everything you need to achieve your fitness goals</p>
          </div>
          <div className="features-grid grid grid-4">
            {features.map((feature, index) => (
              <div key={index} className="feature-card">
                <div className="feature-icon">{feature.icon}</div>
                <h3>{feature.title}</h3>
                <p>{feature.description}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* About Preview Section */}
      <section className="section about-preview">
        <div className="container">
          <div className="about-grid">
            <div className="about-images">
              <img 
                src="https://images.unsplash.com/photo-1571902943202-507ec2618e8f?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80" 
                alt="Gym" 
                className="about-img-1"
              />
              <img 
                src="https://images.unsplash.com/photo-1581009146145-b5ef050c149a?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80" 
                alt="Training" 
                className="about-img-2"
              />
            </div>
            <div className="about-content">
              <h2>We Are <span>PowerFit</span></h2>
              <p>
                Founded in 2008, PowerFit has been transforming lives through fitness 
                for over 15 years. Our mission is to provide a welcoming environment 
                where everyone can achieve their health and fitness goals.
              </p>
              <p>
                With our team of certified trainers, modern equipment, and diverse 
                class offerings, we're committed to helping you become the best 
                version of yourself.
              </p>
              <ul className="about-list">
                <li>✓ Professional certified trainers</li>
                <li>✓ State-of-the-art equipment</li>
                <li>✓ Personalized workout plans</li>
                <li>✓ Nutrition guidance</li>
              </ul>
              <Link to="/about" className="btn btn-primary">
                Learn More <FaArrowRight />
              </Link>
            </div>
          </div>
        </div>
      </section>

      {/* Classes Section */}
      <section className="section classes-section">
        <div className="container">
          <div className="section-title">
            <h2>Our <span>Classes</span></h2>
            <p>Join our variety of fitness classes led by expert instructors</p>
          </div>
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <>
              <div className="grid grid-3">
                {classes.map((gymClass) => (
                  <ClassCard key={gymClass._id} gymClass={gymClass} />
                ))}
              </div>
              <div className="section-cta">
                <Link to="/classes" className="btn btn-secondary">
                  View All Classes <FaArrowRight />
                </Link>
              </div>
            </>
          )}
        </div>
      </section>

      {/* Trainers Section */}
      <section className="section trainers-section">
        <div className="container">
          <div className="section-title">
            <h2>Expert <span>Trainers</span></h2>
            <p>Meet our team of professional fitness instructors</p>
          </div>
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <>
              <div className="grid grid-4">
                {trainers.map((trainer) => (
                  <TrainerCard key={trainer._id} trainer={trainer} />
                ))}
              </div>
              <div className="section-cta">
                <Link to="/trainers" className="btn btn-secondary">
                  View All Trainers <FaArrowRight />
                </Link>
              </div>
            </>
          )}
        </div>
      </section>

      {/* Membership Section */}
      <section className="section membership-section">
        <div className="container">
          <div className="section-title">
            <h2>Membership <span>Plans</span></h2>
            <p>Choose the perfect plan for your fitness journey</p>
          </div>
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <div className="grid grid-3">
              {memberships.map((membership) => (
                <MembershipCard key={membership._id} membership={membership} />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA Section */}
      <section className="section cta-section">
        <div className="container">
          <div className="cta-content">
            <h2>Ready to Start Your <span>Fitness Journey</span>?</h2>
            <p>
              Join PowerFit today and get access to world-class facilities, 
              expert trainers, and a supportive community.
            </p>
            <div className="cta-buttons">
              <Link to="/register" className="btn btn-primary">
                Join Now
              </Link>
              <Link to="/contact" className="btn btn-secondary">
                Contact Us
              </Link>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
